import{f as d,o as r,c as e,a2 as a}from"./chunks/framework.DHYrF-q6.js";const u=JSON.parse('{"title":"16周高级工程师/AI应用工程师面试准备计划","description":"","frontmatter":{},"headers":[],"relativePath":"guide/plan.md","filePath":"guide/plan.md","lastUpdated":1780734044000}'),i={name:"guide/plan.md"};function l(o,t,s,n,h,c){return r(),e("div",null,[...t[0]||(t[0]=[a(`<h1 id="_16周高级工程师-ai应用工程师面试准备计划" tabindex="-1">16周高级工程师/AI应用工程师面试准备计划 <a class="header-anchor" href="#_16周高级工程师-ai应用工程师面试准备计划" aria-label="Permalink to &quot;16周高级工程师/AI应用工程师面试准备计划&quot;">​</a></h1><p>创建日期：2026-06-06</p><blockquote><p>背景：5年Java中级开发经验，Vue了解但不精通，数据库和中间件初中级水平，缺乏高并发/高可用实战经验。目标：冲刺高级工程师 + AI应用工程师岗位。</p></blockquote><h2 id="阶段一-基础夯实-第1-4周" tabindex="-1">阶段一：基础夯实（第1-4周） <a class="header-anchor" href="#阶段一-基础夯实-第1-4周" aria-label="Permalink to &quot;阶段一：基础夯实（第1-4周）&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">阶段目标</p><p>夯实Java核心基础，深入理解JVM、并发编程，掌握常用集合框架源码，理解设计思想和Spring底层原理。为后续进阶打下坚实基础。</p></div><h3 id="第1周-jvm调优与内存模型" tabindex="-1">第1周：JVM调优与内存模型 <a class="header-anchor" href="#第1周-jvm调优与内存模型" aria-label="Permalink to &quot;第1周：JVM调优与内存模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>JVM内存结构（程序计数器、虚拟机栈、本地方法栈、堆、方法区、直接内存）</td><td>⭐</td><td>整理JVM内存结构思维导图</td></tr><tr><td>第2天</td><td>对象创建与内存分配策略、对象访问定位、垃圾回收算法</td><td>⭐</td><td>绘制对象创建过程流程图</td></tr><tr><td>第3天</td><td>垃圾收集器（Serial、Parallel、CMS、G1、ZGC）特点与适用场景</td><td>⭐</td><td>对比表格总结各收集器优缺点</td></tr><tr><td>第4天</td><td>JVM调优参数（-Xms、-Xmx、-Xmn、-XX:+UseGCLogFileRotation等）、GC日志分析</td><td>⭐</td><td>整理常用调优参数清单</td></tr><tr><td>第5天</td><td>内存模型与指令重排序、happens-before规则、volatile原理</td><td>⭐</td><td>编写volatile关键字作用总结</td></tr><tr><td>第6天</td><td>常见OOM问题分析与排查、内存泄漏排查实战</td><td>⭐</td><td>记录3个经典OOM案例分析</td></tr><tr><td>第7周</td><td>模拟生产环境GC调优练习</td><td>⭐</td><td>JVM调优实战报告</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">扩展内容</p><ul><li>学习JMH性能测试工具使用</li><li>阅读OpenJDK源码理解GC实现</li></ul></div><p><strong>本周产出：</strong></p><ul><li><code>docs/jvm-memory-structure.md</code> - JVM内存结构总结</li><li><code>gc-tuning-practice.md</code> - GC调优实战练习记录</li><li>掌握：能清晰阐述GC三色标记算法、增量更新、原始快照的区别</li></ul><h3 id="第2周-并发编程实战" tabindex="-1">第2周：并发编程实战 <a class="header-anchor" href="#第2周-并发编程实战" aria-label="Permalink to &quot;第2周：并发编程实战&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>Java线程实现与线程状态转换、线程生命周期</td><td>⭐</td><td>绘制线程状态转换图</td></tr><tr><td>第2天</td><td>synchronized关键字底层原理、锁升级过程</td><td>⭐</td><td>分析偏向锁→轻量级锁→重量级锁升级过程</td></tr><tr><td>第3天</td><td>ReentrantLock、AQS源码分析（独占锁、共享锁）</td><td>⭐</td><td>梳理AQS CLH队列同步逻辑</td></tr><tr><td>第4天</td><td>CAS原理、ABA问题、原子类（AtomicInteger、LongAdder）</td><td>⭐</td><td>对比CAS和synchronized适用场景</td></tr><tr><td>第5天</td><td>线程池原理、ThreadPoolExecutor参数、线程池调优</td><td>⭐</td><td>编写自定义线程池配置示例</td></tr><tr><td>第6天</td><td>ConcurrentHashMap源码分析（JDK1.8版本）</td><td>⭐</td><td>分段锁原理总结</td></tr><tr><td>第7天</td><td>并发工具类（CountDownLatch、CyclicBarrier、Semaphore）</td><td>⭐</td><td>编写使用案例代码</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">常见坑点</p><ul><li>线程池拒绝策略选择不当导致任务丢失</li><li>死锁场景识别与避免方法</li></ul></div><p><strong>本周产出：</strong></p><ul><li><code>concurrency-practice/src/main/java/com/example/concurrency/</code> - 并发示例代码</li><li><code>docs/aqs-source-analysis.md</code> - AQS源码分析笔记</li><li>掌握：能正确分析并解决常见并发Bug，如可见性、有序性问题</li></ul><h3 id="第3周-集合框架源码与设计模式" tabindex="-1">第3周：集合框架源码与设计模式 <a class="header-anchor" href="#第3周-集合框架源码与设计模式" aria-label="Permalink to &quot;第3周：集合框架源码与设计模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>ArrayList vs LinkedList 源码分析、扩容机制</td><td>⭐</td><td>对比随机访问和插入删除性能</td></tr><tr><td>第2天</td><td>HashMap源码分析、hash碰撞、扩容、红黑树转化</td><td>⭐</td><td>梳理put方法执行流程</td></tr><tr><td>第3天</td><td>LinkedList、ArrayDeque、PriorityQueue源码分析</td><td>⭐</td><td>总结各队列适用场景</td></tr><tr><td>第4天</td><td>红黑树原理、TreeMap、LinkedHashMap实现</td><td>扩展</td><td>理解LinkedHashMap实现LRU缓存</td></tr><tr><td>第5天</td><td>设计模式：单例、工厂、观察者、代理四种核心模式</td><td>⭐</td><td>编写Spring中使用的设计模式示例</td></tr><tr><td>第6天</td><td>设计模式：策略、模板方法、装饰器、责任链</td><td>⭐</td><td>分析Spring MVC中责任链模式应用</td></tr><tr><td>第7天</td><td>设计模式实践：在现有项目中识别重构坏味道</td><td>扩展</td><td>重构示例代码</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">设计模式重点</p><p>面试常问：Spring中用到了哪些设计模式？请举例说明。一定要提前准备好具体例子。</p></div><p><strong>本周产出：</strong></p><ul><li><code>docs/collection-source-analysis.md</code> - 集合源码分析笔记</li><li><code>design-pattern-demo/src/</code> - 设计模式示例代码</li><li>掌握：能讲清HashMap扩容和红黑树转化的全过程</li></ul><h3 id="第4周-spring-boot原理与ioc-aop" tabindex="-1">第4周：Spring Boot原理与IOC/AOP <a class="header-anchor" href="#第4周-spring-boot原理与ioc-aop" aria-label="Permalink to &quot;第4周：Spring Boot原理与IOC/AOP&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>Spring IOC容器原理、Bean生命周期、循环依赖解决</td><td>⭐</td><td>梳理三级缓存解决循环依赖流程</td></tr><tr><td>第2天</td><td>AOP原理、动态代理（JDK+CGLIB）、切点匹配</td><td>⭐</td><td>对比两种动态代理区别</td></tr><tr><td>第3天</td><td>Spring Boot自动配置原理、@Conditional、SPI机制</td><td>⭐</td><td>编写自定义Starter示例</td></tr><tr><td>第4天</td><td>BeanFactory vs ApplicationContext、后置处理器</td><td>⭐</td><td>整理后置处理器执行顺序</td></tr><tr><td>第5天</td><td>Spring事务原理、传播级别、隔离级别、回滚机制</td><td>⭐</td><td>总结常见事务失效场景</td></tr><tr><td>第6天</td><td>Spring Boot启动流程、内嵌容器启动原理</td><td>扩展</td><td>绘制启动流程图</td></tr><tr><td>第7天</td><td>阶段回顾与整理，解答疑难问题</td><td>⭐</td><td>完成阶段自检</td></tr></tbody></table><p><strong>本周产出：</strong></p><ul><li><code>custom-spring-boot-starter/</code> - 自定义Starter项目</li><li><code>docs/spring-ioc-aop-summary.md</code> - Spring核心总结</li><li>掌握：能清晰解释循环依赖为什么需要三级缓存</li></ul><div class="tip custom-block"><p class="custom-block-title">阶段一 Checkpoint</p><ul><li>[ ] 能画出JVM内存结构图并解释各区域作用</li><li>[ ] 能讲解CMS和G1垃圾收集器的区别和适用场景</li><li>[ ] 能说出AQS同步队列的工作原理</li><li>[ ] 能描述HashMap在JDK1.8后的优化点</li><li>[ ] 能解释Spring如何解决循环依赖</li><li>[ ] 能说明Spring Boot自动配置实现原理</li></ul><p>如果少于4个Yes，建议延长1周巩固基础。</p></div><h2 id="阶段二-中间件与数据库-第5-8周" tabindex="-1">阶段二：中间件与数据库（第5-8周） <a class="header-anchor" href="#阶段二-中间件与数据库-第5-8周" aria-label="Permalink to &quot;阶段二：中间件与数据库（第5-8周）&quot;">​</a></h2><h3 id="第5周-mysql深度优化" tabindex="-1">第5周：MySQL深度优化 <a class="header-anchor" href="#第5周-mysql深度优化" aria-label="Permalink to &quot;第5周：MySQL深度优化&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>MySQL体系结构、InnoDB存储引擎结构</td><td>⭐</td><td>绘制InnoDB架构图</td></tr><tr><td>第2天</td><td>B+树索引原理、聚簇索引 vs 非聚簇索引</td><td>⭐</td><td>为什么用B+树而不是B树、哈希？</td></tr><tr><td>第3天</td><td>索引优化、联合索引最左匹配原理、覆盖索引</td><td>⭐</td><td>分析慢SQL优化案例</td></tr><tr><td>第4天</td><td>事务原理、ACID、隔离级别、MVCC实现</td><td>⭐</td><td>讲解MVCC的read view工作机制</td></tr><tr><td>第5天</td><td>锁机制：行锁、间隙锁、表锁、死锁检测</td><td>⭐</td><td>什么情况下会出现间隙锁？</td></tr><tr><td>第6天</td><td>分库分表、分片规则、分布式ID方案</td><td>⭐</td><td>对比各种分布式ID优缺点</td></tr><tr><td>第7天</td><td>慢查询优化实战、explain分析执行计划</td><td>⭐</td><td>优化3个真实慢查询案例</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">面试高频</p><p>为什么InnoDB要使用B+树索引？联合索引最左前缀匹配原则是什么？为什么？这些问题几乎必问。</p></div><p><strong>本周产出：</strong></p><ul><li><code>docs/mysql-optimization-notes.md</code> - MySQL优化笔记</li><li><code>slow-sql-practice/</code> - 慢SQL优化练习</li><li>掌握：能独立分析慢SQL并给出优化方案</li></ul><h3 id="第6周-redis深度应用" tabindex="-1">第6周：Redis深度应用 <a class="header-anchor" href="#第6周-redis深度应用" aria-label="Permalink to &quot;第6周：Redis深度应用&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>Redis数据结构、底层实现（SDS、链表、字典、跳表）</td><td>⭐</td><td>对比各种数据结构适用场景</td></tr><tr><td>第2天</td><td>Redis持久化（RDB、AOF、混合持久化）</td><td>⭐</td><td>对比两种持久化优缺点</td></tr><tr><td>第3天</td><td>Redis缓存问题：击穿、雪崩、穿透解决方案</td><td>⭐</td><td>总结三种问题解决方案对比</td></tr><tr><td>第4天</td><td>Redis集群方案：主从复制、哨兵、Cluster</td><td>⭐</td><td>讲解Cluster槽位映射原理</td></tr><tr><td>第5天</td><td>Redis事务、Lua脚本、缓存一致性问题</td><td>⭐</td><td>分析数据库和缓存双写一致性方案</td></tr><tr><td>第6天</td><td>Redis分布式锁实现、RedLock原理</td><td>⭐</td><td>编写基于Redis的分布式锁</td></tr><tr><td>第7天</td><td>Redis实际应用场景设计</td><td>扩展</td><td>设计一个秒杀库存缓存方案</td></tr></tbody></table><p><strong>本周产出：</strong></p><ul><li><code>docs-redis-depth-summary.md</code> - Redis深度总结</li><li><code>distributed-lock-demo/src/</code> - 分布式锁实现代码</li><li>掌握：能解决缓存一致性、击穿雪崩穿透等常见问题</li></ul><h3 id="第7周-消息队列与分布式理论" tabindex="-1">第7周：消息队列与分布式理论 <a class="header-anchor" href="#第7周-消息队列与分布式理论" aria-label="Permalink to &quot;第7周：消息队列与分布式理论&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>Kafka架构：Broker、Topic、Partition、Offset</td><td>⭐</td><td>ISR副本同步机制原理</td></tr><tr><td>第2天</td><td>Kafka消息存储、零拷贝、索引结构</td><td>⭐</td><td>为什么Kafka性能这么高？</td></tr><tr><td>第3天</td><td>RocketMQ架构、NameServer、Broker、消息过滤</td><td>⭐</td><td>对比Kafka和RocketMQ差异</td></tr><tr><td>第4天</td><td>消息队列幂等性、顺序消息、事务消息</td><td>⭐</td><td>总结常见消息一致性方案</td></tr><tr><td>第5天</td><td>CAP定理、BASE理论、分布式共识</td><td>⭐</td><td>解释CAP为什么不能同时满足</td></tr><tr><td>第6天</td><td>Paxos、Raft协议基本原理</td><td>扩展</td><td>讲解Raft选举过程</td></tr><tr><td>第7天</td><td>分布式ID、分布式事务、2PC、3PC、TCC</td><td>⭐</td><td>对比各种分布式事务方案</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">适用场景选择</p><ul><li>Kafka：高吞吐日志收集、流式处理</li><li>RocketMQ：金融电商、需要事务消息、可靠投递</li><li>RabbitMQ：中小系统、灵活路由</li></ul></div><p><strong>本周产出：</strong></p><ul><li><code>docs/mq-comparison.md</code> - 消息队列对比笔记</li><li><code>distributed-transaction-demo/</code> - 分布式事务示例</li><li>掌握：能解决消息丢失、重复、乱序问题</li></ul><h3 id="第8周-网络与vue基础巩固" tabindex="-1">第8周：网络与Vue基础巩固 <a class="header-anchor" href="#第8周-网络与vue基础巩固" aria-label="Permalink to &quot;第8周：网络与Vue基础巩固&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>TCP/IP四次握手三次挥手、滑动窗口、拥塞控制</td><td>⭐</td><td>为什么四次握手？为什么TIME_WAIT？</td></tr><tr><td>第2天</td><td>HTTP协议、HTTPS、HTTP/2、缓存控制</td><td>⭐</td><td>强缓存vs协商缓存对比</td></tr><tr><td>第3天</td><td>Vue核心：响应式原理、虚拟DOM、Diff算法</td><td>⭐</td><td>Vue2 vs Vue3响应式区别</td></tr><tr><td>第4天</td><td>Vue组件通信、生命周期、路由守卫</td><td>⭐</td><td>总结常见组件通信方式</td></tr><tr><td>第5天</td><td>Vuex/Pinia状态管理、Vue工程化实践</td><td>⭐</td><td>Pinia和Vuex区别</td></tr><tr><td>第6天</td><td>常见Vue性能优化手段</td><td>扩展</td><td>整理Vue性能优化清单</td></tr><tr><td>第7天</td><td>阶段回顾、查漏补缺</td><td>⭐</td><td>完成阶段自检</td></tr></tbody></table><p><strong>本周产出：</strong></p><ul><li><code>docs/network-interview-summary.md</code> - 网络面试总结</li><li><code>vue-demo/</code> - Vue组件示例项目</li><li>掌握：能讲清楚Vue响应式原理和Diff算法</li></ul><div class="tip custom-block"><p class="custom-block-title">阶段二 Checkpoint</p><ul><li>[ ] 能解释MVCC是如何实现的</li><li>[ ] 能优化一条慢SQL，说出优化步骤</li><li>[ ] 能解决缓存和数据库一致性问题</li><li>[ ] 能说出Redis分布式锁的实现和坑点</li><li>[ ] 能解释Kafka ISR机制和零拷贝优化</li><li>[ ] 能对比2PC、TCC、可靠消息最终一致性三种方案</li><li>[ ] 能讲清楚Vue响应式原理</li></ul><p>如果少于5个Yes，建议延长1周巩固。</p></div><h2 id="阶段三-高并发架构-ai应用-第9-12周" tabindex="-1">阶段三：高并发架构 + AI应用（第9-12周） <a class="header-anchor" href="#阶段三-高并发架构-ai应用-第9-12周" aria-label="Permalink to &quot;阶段三：高并发架构 + AI应用（第9-12周）&quot;">​</a></h2><h3 id="第9周-高并发高可用核心技术" tabindex="-1">第9周：高并发高可用核心技术 <a class="header-anchor" href="#第9周-高并发高可用核心技术" aria-label="Permalink to &quot;第9周：高并发高可用核心技术&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>限流算法：计数器、滑动窗口、令牌桶、漏桶</td><td>⭐</td><td>实现滑动窗口限流</td></tr><tr><td>第2天</td><td>降级与熔断：Hystrix、Resilience4j原理</td><td>⭐</td><td>断路器三个状态讲解</td></tr><tr><td>第3天</td><td>负载均衡：Nginx、Ribbon、负载均衡算法</td><td>⭐</td><td>对比几种负载均衡算法</td></tr><tr><td>第4天</td><td>服务发现与注册：Eureka、Nacos、Consul对比</td><td>⭐</td><td>CAP角度分析各组件选择</td></tr><tr><td>第5天</td><td>服务雪崩、链路追踪、OpenTelemetry</td><td>扩展</td><td>了解分布式追踪原理</td></tr><tr><td>第6天</td><td>读写分离、分库分表实战、分片算法设计</td><td>⭐</td><td>设计分库分表方案</td></tr><tr><td>第7天</td><td>高可用集群方案、脑裂问题、选主机制</td><td>⭐</td><td>总结脑裂常见解决方案</td></tr></tbody></table><p><strong>本周产出：</strong></p><ul><li><code>rate-limiter-demo/src/</code> - 限流算法实现</li><li><code>docs/high-availability-summary.md</code> - 高可用总结</li><li>掌握：能设计系统限流降级方案</li></ul><h3 id="第10周-系统设计方法论" tabindex="-1">第10周：系统设计方法论 <a class="header-anchor" href="#第10周-系统设计方法论" aria-label="Permalink to &quot;第10周：系统设计方法论&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>系统设计流程：需求分析→拆分→选型→权衡</td><td>⭐</td><td>掌握设计面试回答框架</td></tr><tr><td>第2天</td><td>常用设计模式：分层架构、CQRS、事件驱动</td><td>⭐</td><td>什么时候用CQRS？</td></tr><tr><td>第3天</td><td>经典设计题：短链接服务设计</td><td>⭐</td><td>完整设计文档</td></tr><tr><td>第4天</td><td>经典设计题：秒杀系统设计</td><td>⭐</td><td>画出架构图</td></tr><tr><td>第5天</td><td>经典设计题：社交Feed流设计</td><td>⭐</td><td>推拉结合方案分析</td></tr><tr><td>第6天</td><td>经典设计题：分布式ID生成系统</td><td>⭐</td><td>对比各种方案优缺点</td></tr><tr><td>第7天</td><td>经典设计题：在线聊天室设计</td><td>扩展</td><td>架构设计文档</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">设计面试技巧</p><p>先谈需求，再谈架构，逐步细化。不要一开始就陷入细节。时刻记住：设计没有标准答案，考察的是思维过程。</p></div><p><strong>本周产出：</strong></p><ul><li><code>docs/system-design-examples/</code> - 多个系统设计文档</li><li>掌握：按照需求-架构-模块-权衡四步法回答设计问题</li></ul><h3 id="第11周-ai基础-rag与langchain" tabindex="-1">第11周：AI基础：RAG与LangChain <a class="header-anchor" href="#第11周-ai基础-rag与langchain" aria-label="Permalink to &quot;第11周：AI基础：RAG与LangChain&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>LLM基础：Transformer、大语言模型原理、Tokenization</td><td>⭐</td><td>理解Transformer编码器解码器结构</td></tr><tr><td>第2天</td><td>RAG基本原理：为什么需要RAG？解决什么问题？</td><td>⭐</td><td>对比RAG和微调优缺点</td></tr><tr><td>第3天</td><td>Embedding模型：Word2Vec → BERT → 现在的Embedding</td><td>⭐</td><td>体验OpenAI Embedding</td></tr><tr><td>第4天</td><td>向量数据库：Chroma、PGVector、Milvus对比</td><td>⭐</td><td>搭建基于PGVector的RAG</td></tr><tr><td>第5天</td><td>RAG优化：多路召回、重排序、HyDE、小分块</td><td>扩展</td><td>实现基础RAG优化</td></tr><tr><td>第6天</td><td>LangChain基础：Chain、PromptTemplate、Retriever</td><td>⭐</td><td>基于LangChain开发问答机器人</td></tr><tr><td>第7天</td><td>LangChain生态：Memory、Agent、Tools</td><td>⭐</td><td>实现带记忆的对话应用</td></tr></tbody></table><p><strong>本周产出：</strong></p><ul><li><code>rag-demo/</code> - 基于LangChain的RAG问答项目</li><li><code>docs/rag-principle-summary.md</code> - RAG原理总结</li><li>掌握：能独立搭建一个基本的RAG应用</li></ul><h3 id="第12周-ai进阶-agent与prompt工程" tabindex="-1">第12周：AI进阶：Agent与Prompt工程 <a class="header-anchor" href="#第12周-ai进阶-agent与prompt工程" aria-label="Permalink to &quot;第12周：AI进阶：Agent与Prompt工程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>Agent基本概念：ReAct框架、思维链（CoT）</td><td>⭐</td><td>理解ReAct推理+行动循环</td></tr><tr><td>第2天</td><td>Agent类型：Plan-and-Execute、Self-Reflection、Reflection</td><td>⭐</td><td>对比不同Agent架构</td></tr><tr><td>第3天</td><td>Tool使用：Function Calling、工具调用格式</td><td>⭐</td><td>开发一个能调用工具的Agent</td></tr><tr><td>第4天</td><td>Multi-Agent架构：多个Agent协作、分工</td><td>扩展</td><td>实现辩论式Multi-Agent</td></tr><tr><td>第5天</td><td>Prompt工程基础：Zero-shot、Few-shot、思维链</td><td>⭐</td><td>总结常用Prompt技巧</td></tr><tr><td>第6天</td><td>高级Prompt技巧：Self-Consistency、Tree-of-Thought</td><td>扩展</td><td>测试对比不同Prompt效果</td></tr><tr><td>第7天</td><td>AI应用项目：开发一个文档问答Agent</td><td>⭐</td><td>完成可演示项目</td></tr><tr><td></td><td>阶段回顾总结</td><td>⭐</td><td>完成阶段自检</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">AI应用工程师重点</p><p>现在AI应用开发非常看重工程落地能力，能把RAG/Agent跑通，做出可用的Demo比理论更重要。一定要动手写代码！</p></div><p><strong>本周产出：</strong></p><ul><li><code>doc-qa-agent/</code> - 文档问答Agent项目</li><li><code>docs/prompt-engineering-summary.md</code> - Prompt工程总结</li><li>掌握：能开发具备工具调用能力的Agent应用</li></ul><div class="tip custom-block"><p class="custom-block-title">阶段三 Checkpoint</p><ul><li>[ ] 能说出四种限流算法的优缺点和适用场景</li><li>[ ] 能画出秒杀系统架构图并说明各个组件作用</li><li>[ ] 能解释RAG解决了大模型什么问题</li><li>[ ] 能独立搭建一个端到端的RAG应用</li><li>[ ] 理解ReAct Agent的工作原理</li><li>[ ] 掌握常用Prompt工程技巧</li><li>[ ] 能讲清楚高并发系统设计的通用套路</li></ul><p>如果少于4个Yes，建议重点补项目实战。</p></div><h2 id="阶段四-冲刺与实战-第13-16周" tabindex="-1">阶段四：冲刺与实战（第13-16周） <a class="header-anchor" href="#阶段四-冲刺与实战-第13-16周" aria-label="Permalink to &quot;阶段四：冲刺与实战（第13-16周）&quot;">​</a></h2><h3 id="第13周-算法刷题冲刺" tabindex="-1">第13周：算法刷题冲刺 <a class="header-anchor" href="#第13周-算法刷题冲刺" aria-label="Permalink to &quot;第13周：算法刷题冲刺&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>数组与双指针：高频题整理</td><td>⭐</td><td>刷15道高频题</td></tr><tr><td>第2天</td><td>链表：反转、快慢指针、环检测</td><td>⭐</td><td>刷12道高频题</td></tr><tr><td>第3天</td><td>二叉树：遍历、递归、BFS、DFS</td><td>⭐</td><td>刷15道高频题</td></tr><tr><td>第4天</td><td>动态规划：背包、子序列、股票问题</td><td>⭐</td><td>刷15道高频题</td></tr><tr><td>第5天</td><td>哈希与滑动窗口：无重复子串、滑动窗口最大值</td><td>⭐</td><td>刷10道高频题</td></tr><tr><td>第6天</td><td>栈与队列、单调栈、括号问题</td><td>⭐</td><td>刷10道高频题</td></tr><tr><td>第7天</td><td>回溯与贪心：排列组合、经典贪心</td><td>⭐</td><td>刷8道高频题</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">算法准备建议</p><p>高级工程师面试一般不会考太偏太难的题，但基础题必须熟练。重点刷LeetCode Hot 100和经典面试题。</p></div><p><strong>本周产出：</strong></p><ul><li><code>algorithm-practice/</code> - 刷题代码整理</li><li><code>docs/algorithm-tips.md</code> - 算法题型套路总结</li><li>目标：Hot 100刷完一遍，重点题二刷</li></ul><h3 id="第14周-系统设计面试深度准备" tabindex="-1">第14周：系统设计面试深度准备 <a class="header-anchor" href="#第14周-系统设计面试深度准备" aria-label="Permalink to &quot;第14周：系统设计面试深度准备&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>分布式缓存系统设计</td><td>⭐</td><td>设计文档 + 架构图</td></tr><tr><td>第2天</td><td>消息队列设计</td><td>⭐</td><td>设计文档 + 架构图</td></tr><tr><td>第3天</td><td>电商订单系统设计</td><td>⭐</td><td>设计文档 + 架构图</td></tr><tr><td>第4天</td><td>搜索系统设计</td><td>扩展</td><td>设计文档 + 架构图</td></tr><tr><td>第5天</td><td>短视频/图片分享服务设计</td><td>⭐</td><td>设计文档 + 架构图</td></tr><tr><td>第6天</td><td>支付系统设计核心要点</td><td>⭐</td><td>总结一致性方案</td></tr><tr><td>第7天</td><td>亿级流量架构设计总结</td><td>⭐</td><td>整理设计面试话术</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">设计题准备方法</p><p>每个设计题按照这个结构准备：1)需求澄清 2)吞吐量QPS估算 3)架构图 4)核心模块 5)瓶颈与优化。</p></div><p><strong>本周产出：</strong></p><ul><li><code>docs/system-design-collection/</code> - 10+系统设计案例整理</li><li>掌握：看到题目就能按框架展开分析</li></ul><h3 id="第15周-项目复盘与简历优化" tabindex="-1">第15周：项目复盘与简历优化 <a class="header-anchor" href="#第15周-项目复盘与简历优化" aria-label="Permalink to &quot;第15周：项目复盘与简历优化&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>STAR法则梳理过往项目</td><td>⭐</td><td>每个项目提炼亮点和挑战</td></tr><tr><td>第2天</td><td>挖掘高并发/高可用相关经验</td><td>⭐</td><td>即使没有大规模，也要提炼设计思路</td></tr><tr><td>第3天</td><td>AI项目经验整合：把RAG/Agent项目加到简历</td><td>⭐</td><td>完善AI项目描述</td></tr><tr><td>第4天</td><td>简历优化：突出技术深度和影响力</td><td>⭐</td><td>量化成果（支撑多少QPS、提升多少性能）</td></tr><tr><td>第5天</td><td>准备自我介绍：1分钟、3分钟版本</td><td>⭐</td><td>熟练背诵</td></tr><tr><td>第6天</td><td>常见面试问题准备：为什么跳槽？期望薪资？</td><td>⭐</td><td>准备好回答话术</td></tr><tr><td>第7天</td><td>模拟面试1对1（找朋友互相面）</td><td>⭐</td><td>记录问题，查漏补缺</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">简历写作技巧</p><ul><li>不要只写做了什么，要写做成了什么，带来什么价值</li><li>用量化数据支撑（支撑10万QPS、性能提升50%、可用性提升到99.95%）</li><li>技术关键词要对，符合招聘JD描述</li></ul></div><p><strong>本周产出：</strong></p><ul><li>优化完成的最新简历</li><li><code>docs/interview-common-questions.md</code> - 常见问题整理</li><li>3分钟自我介绍熟练版本</li></ul><h3 id="第16周-模拟面试与最终冲刺" tabindex="-1">第16周：模拟面试与最终冲刺 <a class="header-anchor" href="#第16周-模拟面试与最终冲刺" aria-label="Permalink to &quot;第16周：模拟面试与最终冲刺&quot;">​</a></h3><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>重点</th><th>产出要求</th></tr></thead><tbody><tr><td>第1天</td><td>基础面试题模拟：Java基础 + JVM + Spring</td><td>⭐</td><td>录制自己回答，找不足</td></tr><tr><td>第2天</td><td>中间件面试模拟：MySQL + Redis + MQ</td><td>⭐</td><td>整理模糊不清的知识点</td></tr><tr><td>第3天</td><td>系统设计模拟：随机抽题，限时完成设计</td><td>⭐</td><td>锻炼口头表达架构能力</td></tr><tr><td>第4天</td><td>AI相关面试：RAG + Agent + LangChain</td><td>⭐</td><td>准备AI项目讲解思路</td></tr><tr><td>第5天</td><td>项目深度挖掘：面试官会追问项目细节</td><td>⭐</td><td>梳理项目中的难点和你的贡献</td></tr><tr><td>第6天</td><td>查漏补缺：回顾整理的错题和模糊点</td><td>⭐</td><td>最后过一遍笔记</td></tr><tr><td>第7天</td><td>调整状态，放松心情</td><td>⭐</td><td>准备迎接面试</td></tr></tbody></table><p><strong>本周产出：</strong></p><ul><li><code>docs/final-review-checklist.md</code> - 最终复习清单</li><li>良好的心态和状态</li></ul><div class="tip custom-block"><p class="custom-block-title">阶段四 Checkpoint</p><ul><li>[ ] LeetCode Hot 100已刷完一遍</li><li>[ ] 10个以上常见系统设计题已准备</li><li>[ ] 简历已优化，突出亮点和量化成果</li><li>[ ] 自我介绍已准备熟练</li><li>[ ] 至少完成3次以上模拟面试</li><li>[ ] 所有知识点都过了一遍</li><li>[ ] AI项目能清晰讲清技术方案和亮点</li></ul><p>准备好了就可以开始投递了！</p></div><h2 id="总体时间分配建议" tabindex="-1">总体时间分配建议 <a class="header-anchor" href="#总体时间分配建议" aria-label="Permalink to &quot;总体时间分配建议&quot;">​</a></h2><p>以下是16周总体时间分配（按每周40小时学习时间计算）：</p><table tabindex="0"><thead><tr><th>领域</th><th>占比</th><th>小时数（16周×40小时=640小时）</th><th>饼图示意</th></tr></thead><tbody><tr><td>Java核心（JVM+并发+Spring）</td><td>25%</td><td>160小时</td><td><code>█████████████████████████</code></td></tr><tr><td>数据库与中间件</td><td>25%</td><td>160小时</td><td><code>█████████████████████████</code></td></tr><tr><td>高并发架构与系统设计</td><td>20%</td><td>128小时</td><td><code>███████████████████</code></td></tr><tr><td>AI应用开发（RAG+Agent）</td><td>15%</td><td>96小时</td><td><code>██████████████</code></td></tr><tr><td>算法刷题</td><td>10%</td><td>64小时</td><td><code>█████████</code></td></tr><tr><td>简历面试准备</td><td>5%</td><td>32小时</td><td><code>█████</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">时间分配说明</p><ul><li>如果你有项目经验，可以适当减少Java基础时间，增加AI和系统设计时间</li><li>如果基础比较薄弱，建议适当延长基础阶段，不要急于赶进度</li><li>每天建议学习3-4小时，周末多学一些，总共每周约20-40小时</li></ul></div><h2 id="每周学习建议" tabindex="-1">每周学习建议 <a class="header-anchor" href="#每周学习建议" aria-label="Permalink to &quot;每周学习建议&quot;">​</a></h2><ol><li><strong>每日任务量</strong>：每天3-4小时，不要熬夜突击，保持节奏更重要</li><li><strong>动手实践</strong>：理论一定要配合代码实践，看懂了不代表会写了</li><li><strong>记笔记</strong>：好记性不如烂笔头，整理成Markdown笔记方便复习</li><li><strong>总结复盘</strong>：每周日花1小时回顾本周内容，整理疑难问题</li><li><strong>项目驱动</strong>：学习每个知识点后，尽量找机会做小项目验证</li></ol><h2 id="推荐资料" tabindex="-1">推荐资料 <a class="header-anchor" href="#推荐资料" aria-label="Permalink to &quot;推荐资料&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">核心资料</p><ul><li><strong>Java基础</strong>：《深入理解Java虚拟机》、《Java并发编程实战》</li><li><strong>数据库</strong>：《MySQL技术内幕：InnoDB存储引擎》</li><li><strong>架构</strong>：《架构整洁之道》、《分布式服务架构：原理、设计与实战》</li><li><strong>AI</strong>：LangChain官方文档、DeepLearning.AI LangChain专项课程</li><li><strong>算法</strong>：LeetCode Hot 100</li></ul></div><h2 id="学习路线图" tabindex="-1">学习路线图 <a class="header-anchor" href="#学习路线图" aria-label="Permalink to &quot;学习路线图&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阶段一：基础夯实 → 阶段二：中间件数据库 → 阶段三：高并发+AI → 阶段四：冲刺面试</span></span>
<span class="line"><span>   4周               4周                  4周               4周</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>坚持16周，你就能从Java中级进阶到高级+AI应用工程师方向，加油！</p>`,97)])])}const b=d(i,[["render",l]]);export{u as __pageData,b as default};
